// pubspec.yaml:
//   dependencies:
//     drift: ^2.20.0
//     sqlite3_flutter_libs: ^0.5.24
//     path_provider: ^2.1.4
//     path: ^1.9.0
//   dev_dependencies:
//     drift_dev: ^2.20.0
//     build_runner: ^2.4.13

// lib/db/database.dart
import 'package:drift/drift.dart';
import 'package:drift/native.dart';
import 'package:path_provider/path_provider.dart';
import 'package:path/path.dart' as p;
import 'dart:io';

part 'database.g.dart';

// ============ Tables ============
class Users extends Table {
  IntColumn      get id        => integer().autoIncrement()();
  TextColumn     get email     => text().withLength(min: 3, max: 255).unique()();
  TextColumn     get name      => text().withLength(min: 1, max: 100)();
  DateTimeColumn get createdAt => dateTime().withDefault(currentDateAndTime)();
}

class Orders extends Table {
  IntColumn      get id          => integer().autoIncrement()();
  IntColumn      get userId      => integer().references(Users, #id)();
  IntColumn      get totalCents  => integer().check(totalCents.isBiggerThanValue(0))();
  TextColumn     get status      => text().withDefault(const Constant('pending'))();
  DateTimeColumn get createdAt   => dateTime().withDefault(currentDateAndTime)();

  @override
  List<Set<Column>> get uniqueKeys => [{userId, createdAt}];

  @override
  List<String> get customConstraints => [
    'CHECK (status IN (\'pending\', \'paid\', \'cancelled\'))',
  ];
}

// ============ DAO — partition queries per feature ============
@DriftAccessor(tables: [Users, Orders])
class UserDao extends DatabaseAccessor<AppDatabase> with _$UserDaoMixin {
  UserDao(super.db);

  Future<List<User>> allUsers() => select(users).get();

  Stream<List<User>> watchAllUsers() =>
      (select(users)..orderBy([(u) => OrderingTerm.desc(u.createdAt)])).watch();

  Future<User?> byEmail(String email) =>
      (select(users)..where((u) => u.email.equals(email))).getSingleOrNull();

  // JOIN — top spenders
  Future<List<UserSpending>> topSpenders({int limit = 10}) async {
    final query = select(users).join([
      leftOuterJoin(orders, orders.userId.equalsExp(users.id)),
    ])
      ..groupBy([users.id])
      ..orderBy([OrderingTerm.desc(orders.totalCents.sum())])
      ..limit(limit);

    return (await query.get()).map((row) => UserSpending(
      user: row.readTable(users),
      totalCents: row.read(orders.totalCents.sum()) ?? 0,
    )).toList();
  }

  // Insert
  Future<int> add(String email, String name) =>
      into(users).insert(UsersCompanion.insert(email: email, name: name));

  // Transaction — atomic ops
  Future<int> placeOrder(int userId, int totalCents) =>
      transaction(() async {
        final orderId = await into(orders).insert(OrdersCompanion.insert(
          userId: userId, totalCents: totalCents,
        ));
        return orderId;
      });
}

class UserSpending {
  UserSpending({required this.user, required this.totalCents});
  final User user;
  final int totalCents;
}

// ============ Database ============
@DriftDatabase(tables: [Users, Orders], daos: [UserDao])
class AppDatabase extends _$AppDatabase {
  AppDatabase() : super(_openConnection());

  @override int get schemaVersion => 2;

  // Migration when schemaVersion bumps
  @override
  MigrationStrategy get migration => MigrationStrategy(
    onCreate: (m) => m.createAll(),
    onUpgrade: (m, from, to) async {
      if (from < 2) {
        // v1 -> v2 — add a column
        await m.addColumn(users, users.createdAt);
      }
    },
    beforeOpen: (details) async {
      await customStatement('PRAGMA foreign_keys = ON');
    },
  );

  static QueryExecutor _openConnection() {
    return LazyDatabase(() async {
      final dbFolder = await getApplicationDocumentsDirectory();
      final file = File(p.join(dbFolder.path, 'app.sqlite'));
      return NativeDatabase.createInBackground(file);   // background isolate!
    });
  }
}

// Run: dart run build_runner build --delete-conflicting-outputs
// Generates database.g.dart with typed User, Order, companions, DAO mixins.

// ============ Widget consumption — reactive by default ============
StreamBuilder<List<User>>(
  stream: db.userDao.watchAllUsers(),
  builder: (ctx, snap) => ListView.builder(
    itemCount: snap.data?.length ?? 0,
    itemBuilder: (_, i) => ListTile(title: Text(snap.data![i].name)),
  ),
);
// Insert a user anywhere in the app → this stream emits → list rebuilds.
// That's the offline-first Flutter dream, achieved with 5 lines of widget code.

// Each schemaVersion bump requires migration logic.
// v1: initial schema.
// v2: added Users.createdAt.
// v3: rename Orders.total → totalCents.

@override
MigrationStrategy get migration => MigrationStrategy(
  onCreate: (m) => m.createAll(),

  onUpgrade: (m, from, to) async {
    if (from < 2) {
      await m.addColumn(users, users.createdAt);
    }
    if (from < 3) {
      // Rename requires table rebuild in SQLite (works transparently in Drift).
      // Use runCustom for anything Drift can't express directly.
      await customStatement('ALTER TABLE orders RENAME COLUMN total TO totalCents');
    }
  },

  beforeOpen: (details) async {
    // Enable FKs (OFF by default in SQLite!)
    await customStatement('PRAGMA foreign_keys = ON');
    // Enable WAL for concurrent readers/writers.
    await customStatement('PRAGMA journal_mode = WAL');
  },
);

// Drift provides a MIGRATION TEST API:
// - Load a schema at v1
// - Insert sample data
// - Run onUpgrade to v3
// - Verify data is preserved + schema is valid
// This is a superpower — silent migration bugs are the worst kind.

